let arr = ['apple', 'banana', 'cherry', 'banana'];
arr = arr.filter(item => item !== 'banana');
console.log(arr); // Expected output: ['apple', 'cherry']

let arr = ['apple', 'banana', 'cherry'];
arr.reverse();
console.log(arr); // Expected output: ['cherry', 'banana', 'apple']

let arr = [1, 2, 3, 4, 5];
arr = arr.map(num => num * 2);
console.log(arr); // Expected output: [2, 4, 6, 8, 10]

let arr = [10, 5, 3, 8, 2];
let min = Math.min(...arr);
console.log(min); // Expected output: 2

let arr = [10, 5, 3, 8, 2];
let isExists = arr.some(num => num >= 5);
console.log(isExists); // Expected output: true

let arr = [10, 5, 3, 8, 2];
let isAll = arr.every(num => num >= 5);
console.log(isAll); // Expected output: false

let arr = ['Hello', 'World'];
let str = arr.join(' ');
console.log(str); // Expected output: 'Hello World'

let arr = ['apple', 'banana', 'apple', 'orange', 'banana'];
let uniqueArr = [...new Set(arr)];
console.log(uniqueArr); // Expected output: ['apple', 'banana', 'orange']

let arr = [5, 3, 8, 1, 2];
arr.sort((a, b) => a - b);
console.log(arr); // Expected output: [1, 2, 3, 5, 8]

let arr = [1, 2, 3, 4, 5];
arr.reverse();
console.log(arr); // Expected output: [5, 4, 3, 2, 1]

