let isAllEven = arr.every(num => num % 2 === 0);
console.log(isAllEven); // Expected output: true

let arr = [5, 10, 15, 20, 25];
let firstOver10 = arr.find(num => num >= 10);
console.log(firstOver10); // Expected output: 10

